import React, { useState, useCallback } from 'react';
import {Grid, Row, Col} from 'react-bootstrap';
import Gallery from "react-photo-gallery";
import Carousel, { Modal, ModalGateway } from "react-images";



import './style.css'

const photos = [
    {
      src: "https://lapisdenoiva.com/wp-content/uploads/2018/02/casamento-intimista-no-canto-das-heras-17-800x533.jpg",
      width: 4,
      height: 3
    },
    {
      src: "https://d2uzqu0gkpnx87.cloudfront.net/site/uploads/2017/09/14/21751988_1292281524215326_1984551961336793259_n.jpg",
      width: 1,
      height: 1
    },
    {
      src: "https://imagens-revista.vivadecora.com.br/uploads/2018/08/ideia-de-bolo-para-festa-de-15-anos-decorado-com-tons-past%C3%A9is-e-flores.jpg",
      width: 3,
      height: 5
    },
    {
      src: "https://static.baratocoletivo.com.br/2018/1210/10018001/g_jf-giardino-buffet58c5cb2ac8.jpg",
      width: 5,
      height: 4
    },
    {
      src: "http://www.revistasulfashion.com.br/uploads/imagens/dhulian-trombim-15-anos1.jpg",
      width: 5,
      height: 3
    },
    {
    src: "https://lapisdenoiva.com/wp-content/uploads/2018/02/casamento-intimista-no-canto-das-heras-17-800x533.jpg",
    width: 4,
    height: 3
    },
    {
    src: "https://d2uzqu0gkpnx87.cloudfront.net/site/uploads/2017/09/14/21751988_1292281524215326_1984551961336793259_n.jpg",
    width: 1,
    height: 1
    },
    {
    src: "https://imagens-revista.vivadecora.com.br/uploads/2018/08/ideia-de-bolo-para-festa-de-15-anos-decorado-com-tons-past%C3%A9is-e-flores.jpg",
    width: 3,
    height: 5
    },
    {
    src: "https://static.baratocoletivo.com.br/2018/1210/10018001/g_jf-giardino-buffet58c5cb2ac8.jpg",
    width: 5,
    height: 4
    },
    {
    src: "http://www.revistasulfashion.com.br/uploads/imagens/dhulian-trombim-15-anos1.jpg",
    width: 5,
    height: 3
    }      
  ];


function Galeria(){
    const [currentImage, setCurrentImage] = useState(0);
    const [viewerIsOpen, setViewerIsOpen] = useState(false);

    const openLightbox = useCallback((event, { photo, index }) => {
    setCurrentImage(index);
    setViewerIsOpen(true);
    }, []);

    const closeLightbox = () => {
    setCurrentImage(0);
    setViewerIsOpen(false);
    };

    return (<div id="galeria">
        <Grid>
            <Row>
                <Col md={12} xs={12}>
                    <div className="contatoTitle-container">
                    <h1 className="contato-title welcome">Galeria</h1>
                    </div>
                </Col>
            </Row>
        </Grid>
        {/* https://neptunian.github.io/react-photo-gallery/ */}
        <Gallery id="photos" photos={photos} onClick={openLightbox} direction={"column"}/>
        <ModalGateway>
          {viewerIsOpen ? (
            <Modal onClose={closeLightbox}>
              <Carousel
                currentIndex={currentImage}
                views={photos.map(x => ({
                  ...x,
                  srcset: x.srcSet,
                  caption: x.title
                }))}
              />
            </Modal>
          ) : null}
        </ModalGateway>
  </div>)
}

export default Galeria;