import React from 'react';
import './style.css'
import {Carousel} from 'react-bootstrap';

import img1 from './assets/slide1.jpg';
import img2 from './assets/slide2.jpg';
import img3 from './assets/slide3.jpg';
import img4 from './assets/slide4.jpg';
import img5 from './assets/slide5.jpg';

var Background1 ={
  backgroundImage: 'url(' + img1 + ')'
};
var Background2 ={
  backgroundImage: 'url(' + img2 + ')'
};
var Background3 ={
  backgroundImage: 'url(' + img3 + ')'
};
var Background4 ={
  backgroundImage: 'url(' + img4 + ')'
};
var Background5 ={
  backgroundImage: 'url(' + img5 + ')'
};

const CarouselSlide = () => <fragment>
 <Carousel controls={false} className="carouselEl">
<Carousel.Item>
<div className="parallax" style={Background1}></div>
  <Carousel.Caption>
    <h3>UMA EMPRESA<br />
CONSTRUÍDA POR <br />
MAIS DE 27 MIL<br />
COLABORADORES</h3>
  </Carousel.Caption>
</Carousel.Item>
<Carousel.Item>
<div className="parallax" style={Background2}></div>
  <Carousel.Caption>
    <h3>EM 1 ANO, IMPLANTAMOS<br />
      7 MIL QUILÔMETROS<br />
      DE FIBRA ÓPTICA E FIZEMOS<br />
      MAIS DE 128 MIL QUILÔMETROS<br />
      EM MANUTENÇÃO DE REDE DA OI</h3>
  </Carousel.Caption>
</Carousel.Item>
<Carousel.Item>
<div className="parallax" style={Background3}></div>
  <Carousel.Caption>
    <h3>SEREDE E REDE CONECTA,<br />
CADA MARCA RESPONSÁVEL<br />
POR SUA ÁREA DE ATUAÇÃO,<br />
PRESERVANDO O OBJETIVO<br />
COMUM. ISSO É SINERGIA!</h3>
  </Carousel.Caption>
</Carousel.Item>
<Carousel.Item>
<div className="parallax" style={Background4}></div>
  <Carousel.Caption>
    <h3>MAIS DE 12 MILHÕES <br />
DE CLIENTES ATENDIDOS<br />
POR ANO</h3>
  </Carousel.Caption>
</Carousel.Item>
<Carousel.Item>
<div className="parallax" style={Background5}></div>
  <Carousel.Caption>
    <h3>ESTAMOS PRESENTES<br />
EM MAIS DE 3.300<br />
MUNICÍPIOS NO BRASIL</h3>
  </Carousel.Caption>
</Carousel.Item>
</Carousel>
  </fragment>;

export default CarouselSlide;
