import React from 'react';
import {Navbar, Nav, NavItem} from 'react-bootstrap';
import logo from './assets/logo.png';
import './style.css'

const Menu = () => <Navbar fixedTop collapseOnSelect fluid className="responsiveMenu">
<Navbar.Header>
    <Navbar.Brand>
        <a href="#home">         
            <img src={logo} className="logo-empresas" alt="logo" />
        </a>
    </Navbar.Brand>
  <Navbar.Toggle />
</Navbar.Header>
<Navbar.Collapse  className="collapseMenu">
    <Nav pullRight className="menuItem">
    <NavItem eventKey={1} href="#home">
        INÍCIO
    </NavItem>
    <NavItem className="menuEl" eventKey={2} href="#casa">
        A CASA
    </NavItem>
    <NavItem className="menuEl" eventKey={2} href="#servicos">
        SERVIÇOS
    </NavItem>
    <NavItem className="menuEl" eventKey={2} href="#galeria">
        GALERIA
    </NavItem>
    <NavItem className="menuEl" eventKey={2} href="#como-chegar">
        COMO CHEGAR
    </NavItem>
    <NavItem className="menuEl" eventKey={2} href="#contato">
        CONTATO
    </NavItem>
    </Nav>
</Navbar.Collapse>
</Navbar>

export default Menu;