import React from 'react';
import {Grid, Row, Col, Carousel} from 'react-bootstrap';

import './style.css'

import img1 from './assets/salao.jpg';

var Background1 ={
    backgroundImage: 'url(' + img1 + ')'
  };
  var Background2 ={
    backgroundImage: 'url(' + img1 + ')'
  };
  var Background3 ={
    backgroundImage: 'url(' + img1 + ')'
  };
  var Background4 ={
    backgroundImage: 'url(' + img1 + ')'
  };
  var Background5 ={
    backgroundImage: 'url(' + img1 + ')'
  };

const Casa = () =>  <div className="casa-container">
        <Grid>
            <Row id="casa">
                <Col md={12} xs={12}>
                    <div className="contatoTitle-container">
                    <h1 className="contato-title welcome">Nossa Casa</h1>
                    </div>
                </Col>
            </Row>
            <div className="casa-grid">
                <Row>
                    <Col md={6} xs={12}>
                        <center>
                            <h3 className="casa-title">Um espaço para chamar de seu</h3>
                        </center>
                        <div className="casa-text">
                            Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry's standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book. It has survived not only five centuries, but also the leap into electronic typesetting, remaining essentially unchanged. It was popularised in the 1960s with the release of Letraset sheets containing Lorem Ipsum passages, and more recently with desktop publishing software like Aldus PageMaker including versions of Lorem Ipsum.
                        </div>
                    </Col>
                    <Col md={6} xs={12}>
                    <Carousel controls={false} class="image-casa-container">
                        <Carousel.Item>
                            <div className="casa-parallax" style={Background1}></div>
                        </Carousel.Item>
                        <Carousel.Item>
                            <div className="casa-parallax" style={Background2}></div>
                        </Carousel.Item>
                        <Carousel.Item>
                            <div className="casa-parallax" style={Background3}></div>
                        </Carousel.Item>
                        <Carousel.Item>
                            <div className="casa-parallax" style={Background4}></div>
                        </Carousel.Item>
                        <Carousel.Item>
                            <div className="casa-parallax" style={Background5}></div>
                        </Carousel.Item>
                        </Carousel>
                    </Col>
                </Row>
            </div>
        </Grid>
    </div>
    


export default Casa;