import React, { Component } from 'react';
import {Grid, Row, Col} from 'react-bootstrap';
import './style.css';

import axios from 'axios';
const API_PATH = 'http://serede.com.br/api/mail.php';



class IframeComponent extends React.Component {
  render() {
    return (
      <iframe 
        src={`https://maps.google.com/maps?q=${encodeURI(this.props.location)}&t=&z=13&ie=UTF8&iwloc=&output=embed`} 
        frameborder="0" 
        scrolling="no" 
        marginheight="0" 
        marginwidth="0" 
        height={this.props.height} 
        width={this.props.width} 
        className="fullheight"
      />
    )
  }
}

class Contato extends Component {
    constructor(props) {
        super(props);
        this.state = {
          fname: '',
          subject: '',
          email: '',
          message: '',
          mailSent: false,
          error: null
        }
      }
    
      handleFormSubmit = e => {
        e.preventDefault();

        var fname = this.state.fname;
        var subject = this.state.subject;
        var email = this.state.email;
        var message = this.state.message;

        axios.post(`${API_PATH}`, null, { params: {
            fname,
            subject,
            email,
            message
          }})
        .then(result => {
        this.setState( { 
            mailSent: result.data.sent
        })
          console.log(this.state);
        })
        .catch(error => this.setState( { error: error.message } ));
        };
    
      render() {
        return (
          <Grid className="contato-container" fluid>
          <Row id="como-chegar">
              <Col xs={12} md={12} >
              <IframeComponent
                location="Teodoro da Silva 701 - Vila Isabel, RJ" 
                height="600px" 
                width="100%"
              />
              </Col >
          </Row>
          <Row id="contato">
            <Col md={12} xs={12}>
              <div className="contatoTitle-container">
                <h1 className="contato-title welcome">Contato</h1>
              </div>
            </Col>
          </Row>
          <Col md={6} xs={12}>
            <Row>
              {/* <div className="contatoTitle-container">
                <h1 className="contato-title welcome">Como Chegara</h1>
              </div> */}
            </Row>
            <Row>
              <Col className="container-address" md={12} xs={6}>
                <Row ><center><h2 className="subtitleAddress">Aguardamos seu contato!</h2></center></Row>
                <Row><center className="rowSpacing">Conheça nosso espaço, tire dúvidas e faça sugestões através do formulário de contato ao lado ou telefones e e-mail abaixo.</center></Row>
              </Col>
            </Row>
            <Row>
              <Col className="container-address" md={12} xs={6}>
                <Row><strong>Endereço: </strong>Rua Teodoro da Silva, 701 - Vila Isabel, Rio de Janeiro.</Row>
                <Row><strong>Telefones para contato: </strong>(21) 99999-9999 e (21) 2766-0000</Row>
                <Row><strong>E-mail: </strong>contato@netoshouse.com.br</Row>
              </Col>
            </Row>
            <Row>
            <center>
                <h3 className="subtitleAddress">Nossas Redes Sociais</h3>
              </center>
            <div className="socialContainer">
              <div className="socialIcon">
                <a href="http://facebook.com" target="_blank">
                  <i className="fab fa-facebook-square svgIcon"></i>
                </a>
              </div>
              <div className="socialIcon">
                <a href="http://instagram.com" target="_blank">
                  <i className="fab fa-instagram svgIcon"></i>
                </a>
              </div>
              <div className="socialIcon">
                <a href="http://whatsapp.com" target="_blank">
                  <i className="fab fa-whatsapp svgIcon"></i>
                </a>
              </div>
            </div>
            </Row>
          </Col>
          <Col md={6} xs={12}>
            <Row>
            <Col className="contatoForm" xs={12} md={12}>
              <form action="#">
                <div>
                  <input type="text" className="contatoInput" id="fname" name="firstname" placeholder="Nome" 
                  value={this.state.fname }
                  onChange={e => this.setState({ fname: e.target.value })}

                  />
                </div>
                  <input type="email"  className="contatoInput" id="email" name="email" placeholder="E-mail"
                  value={this.state.email} 
                  onChange={e => this.setState({ email: e.target.value })}
                  />
                <div>
                  <input type="text"  className="contatoInput" id="subject" name="lastname" placeholder="Assunto" 
                  value={this.state.subject}
                  onChange={e => this.setState({ subject: e.target.value })}
                  />
                </div>  
                <div>
                  <textarea id="message"  className="contatoInput mensagemInput"  name="message" placeholder="Mensagem"
                  onChange={e => this.setState({ message: e.target.value })}
                  value={this.state.message}
                  ></textarea>
                  </div>
                  <div>
                  <input 
                  type="submit" 
                  className="mensagemBotao g-recaptcha" 
                  onClick = {e => this.handleFormSubmit(e)} 
                  data-sitekey="6LfRFbwUAAAAAFDK40YM75S7WV91xABkAymJdptB" 
                  data-callback='onSubmit'
                  value="ENVIAR" />
                  </div>
                  <div> 
                    {this.state.mailSent &&
                      <div className="ok">Obrigado pelo contato! Em breve retornaremos.</div>
                     } 
                     {this.state.error  &&
                      <div className="error">Erro ao enviar mensagem, tente novamente</div>
                     }
                  </div>
              </form>
            </Col>
            </Row>
          </Col>
          <Row> 
            
          </Row>
          </Grid>
        );
      }
    }

export default Contato;


