import React from 'react';
import {Grid, Row, Col} from 'react-bootstrap';
import './style.css';

import logo from '../Menu/assets/logo.png'

const Rodape = () => <Grid className="rodape-container" fluid>
  <Row>
      <Col xs={4} md={4}>
          <img className="logo-empresas-rodape"  src={logo} />
      </Col>
      <Col xs={8} md={8}>
        <p className="rodape-text">
          Made with <span role="img" aria-label="hearth">❤️</span> 
          by <a href="http://celsoinacio.com.br">Celso Inácio</a>.
        </p>  
      </Col>
  </Row>
</Grid>;

export default Rodape;